insert into quotes (author, quote, source, topic) values
  ('ილია ჭავჭავაძე', 'ჩვენი თავი ჩვენადვე გვეყუდნეს!', 'მგზავრის წერილები', 'თავისუფლება'),
  ('კონსტანტინე გამსახურდია', 'როცა ხალხს ამდენი მოღალატე შინა ჰყავს, მაკედონელიც ვერ გაამარჯვებინებს მას!', 'დიდოსტატის მარჯვენა', 'ღალატი'),
  ('შოთა რუსთაველი', 'ბოროტსა სძლია კეთილმან, არსება მისი გრძელია!', 'ვეფხისტყაოსანი', 'სიკეთე'),
  ('აკაკი წერეთელი', 'გული თუ გატყდა, შესაძლებელიც აღარ სჯერა!', 'თამარ ცბიერი', 'იმედგაცრუება'),
  ('ჭაბუა ამირეჯიბი', 'ცხოვრება ის არის, რაც გახსოვს. დანარჩენი არსებობაა.', 'დათა თუთაშხია', 'ცხოვრებისეული'),
  ('გალაკტიონ ტაბიძე', 'მძიმეა ტვირთი? მაშ სხვებმა ზიდონ…', 'ის მოდიოდა ქუჩაში ერთი', 'ცხოვრებისეული'),
  ('ჯემალ ქარჩხაძე', 'სიმართლე შეგიძლია გვემო, ხაროში ჩააგდო და ზემოდან მიწა გადააფარო. ან არადა, ლაქი წაუსვა, ვერცხლის წყალში ამოავლო, ლამაზ ქათქათა ტყუილში გაახვიო, მაგრამ მოკვლით ვერ მოკლავ. სუნთქვას ვერ შეუკრავ. სიმართლის სუნთქვა მაინც გესმის, ცდილობ ყური არ ათხოვო და მაინც გესმის, როგორც საათის წიკწიკი სამარისებულ სიჩუმეში.', 'მდგმური', 'სიმართლე, ცხოვრებისეული'),
  ('გურამ დოჩანაშვილი', 'დედამიწას სიყვარული ატრიალებს, დომენიკო..', 'სამოსელი პირველი', 'სიყვარული'),
  ('ვაჟა–ფშაველა', 'მუტრუკი მიტომ მუტრუკობს, დედა ჰყოლია ვირიო. კაცი ბეჩავის მჩაგრავი სად გაგონილა გმირიო?!', 'მუტრუკი მიტომ მუტრუკობს', 'სამაგალითო'),
  ('ჭაბუა ამირეჯიბი', 'ყველა კაცი თავის საქმეს მისდევს, ჭკუა ბევრისთვის მიუცია ღმერთს, გაგება ცოტასთვის. გაგება როგორიც აქვს ადამიანს, ისეთ საქმეს მიჰყვება და არის.', 'დათა თუთაშხია', 'ცხოვრებისეული'),
  ('ნოდარ დუმბაძე', 'ყველაზე დიდი გამოგონება ქვეყანაზე: ანბანი, ჰიმნი და დროშაა. რადგან სამთავე თავისუფლების სათავეა.', 'თეთრი ბაირაღები', ''),
  ('კონსტანტინე გამსახურდია', 'ვინც შეგირდი არ ყოფილა, ვერასოდეს გახდება ოსტატი. ვერც იგი გახდება ოდესმე ოსტატი, მუდამ ოსტატებს ვინც შეჰყურებს პირში.', 'დიდოსტატის მარჯვენა', ''),
  ('უცნობი', 'მგელი უნდა იყო, მგელი და მგელზე უფრო მგელი. ცხოვრება ომია, ომში კი ძლიერები იმარჯვებენ.', 'ლონდრე', ''),
  ('უცნობი', 'არ გაბედო სიკვდილი, სანამ ცოცხალი ხარ', 'ფესვები', ''),
  ('გიორგი ლეონიძე', 'ქვეყანას სამი რამ აკლია: ცას კიბე, ზღვას ხიდი, ადამიანს კი სამართალი.', 'ნატვრის ხე', 'ადამიანი'),
  ('უცნობი', 'ყოველ სამ კაცში ოთხი მტერია', 'მონანიება', ''),
  ('ჭაბუა ამირეჯიბი', 'ათასნაირი ხელქვეითი მყოლია და მათში ყველაზე პუნქტუალურს, მუყაითსა და დამჯერს მაინც ფანტაზიის მქონე, თავის საქმეზე შეყვარებული და თუნდაც რამდენადმე თავნება ხელქვეითი მირჩევნია. ასეთისგან საქმის წახდენაც არ არის მოულოდნელი, მაგრამ მათი მოქმედება მუდამ მშვენიერი და პერსპექტიულია. დიახ, პერსპექტიული, რადგან სწორედ ეს ადამიანები ამდიდრებენ კაცობრიობის გამოცდილებას, ხვეწენ პროფესიონალიზმს, ხელოვნებად, თავისუფალ შემოქმედებად აქცევენ სამსახურეობრივ საქმეს. ', 'დათა თუთაშხია', ''),
  ('კონსტანტინე გამსახურდია', 'ძლიერს უფრო მეტად უჭირს ამ ქვეყნად. ამიტომაც მუდამ დაღრენილნი დადიან ლომები, ვეფხვები და ავაზები, ხოლო თრითინები, თაგვები და ციყვები მუდამ მხიარულად დაცუნცულებენ.', 'დიდოსტატის მარჯვენა', ''),
  ('ნიკოლოზ ბარათაშვილი', 'სასაცილოა, ბერიკაცი რომ ყმაწვილობდეს და საბრალოა, როს ჭაბუკი ბერიკაცობდეს!', 'ჩემთ მეგობართ', ''),
  ('იაკობ გოგებაშვილი', 'რამდენადაც უფრო დიდია ხალხის სიღარიბე, იმდენად უფრო ესაჭიროება სკოლა, რომელიც სამართლიანად ითვლება სიღარიბის უებარ წამლად.', '', ''),
  ('სულხან–საბა ორბელიანი', 'კაცი, სახელის მძებნელი, უკვდავად შემირაცხია, მკვდრად იგი თქმულა, ვის ვაი სახელი ზედ არ აცხია.', '', ''),
  ('სულხან–საბა ორბელიანი', 'ადამიანი უნდა ფასდებოდეს „საქმითა და აღსრულებითა“. “საქმე სიტყვიანი და სიტყვა საქმიანი“.', '', ''),
  ('სულხან–საბა ორბელიანი', 'საქმე სიტყვიანი და სიტყვა საქმიანი.', '', ''),
  ('სულხან–საბა ორბელიანი', 'კარგი ამხანაგი ადვილად არ იშოვების, გზაზედ ცუდად არ იპოვების, იაფად ვერავინ იყიდის.', 'სიბრძნე სიცრუისა', ''),
  ('ზაალ სამადაშვილი', 'ვცდილობ განვახორციელო პრინციპი: როცა არ მოგწონს სხვის მიერ გაკეთებული საქმე, შეეცადე შენ თვითონ გააკეთო უკეთესად. კამათში დაღლას შრომით დაღლა მირჩევნია.', '', ''),
  ('ტარიელ ჭანტურია', 'ყველაფერი, რაც კლასიკოსის ხელიდანაა გამოსული, კლასიკა არ არის. როცა რომელიმე ჩვენგანი გაცხარებული ლანძღავს გალაკტიონის ზოგიერთ ლექსს, იგი გალაკტიონს არ ლანძღავს.', '', ''),
  ('ზურაბ ჟვანია', 'მე ვარ ქართველი და მაშასადამე, ვარ ევროპელი!', '', 'პატრიოტიზმი'),
  ('ნოე ჟორდანია', 'შეხვდით 26 მაისს და გაიგებთ თუ რა ძალა აქვს თავისუფლებას.', '', ''),
  ('ნოე ჟორდანია', 'ყველაზე უფრო აღსაშფოთებელია ის, რომ ახალგაზრდობას არ ამზადებენ, არ ასწავლიან ყველაზე უფრო საჭირო, აუცილებელ, თვით ცხოვრების და სიცოცხლისათვის აუცილებელ სწავლა-ცოდნას, არ ამზადებენ სქესთა ურთიერთობის ნორმალურ აწყობას. ეს არის მიჩნეული სირცხვილათ, დასამალავათ, ვითომ ის უცაბედი, წარმავალი მოვლენაა. ორივე სქესი მიშვებულია თავის ფანტაზიაზე, თავის გემოვნებაზე, თავის წარმოდგენებზე — და ასე საფუძველი საზოგადოების — ოჯახი — შენდება შემთხვევაზე.', 'წიგნი ოჯახში საკითხავი“, გვ. 23', ''),
  ('ნოე ჟორდანია', 'მეფე ისეთივე გამოგონილი ავტორიტეტია, როგორც ღმერთი. ეს ორთავე ერთ დონეზე დავაყენე, ათეიზმი და რესპუბლიკანიზმი ერთიმეორის ტყუპათ დავსახე.', '„ჩემი წარსული“, გვ. 12', ''),
  ('ნოე ჟორდანია', 'ერთხელ ჩამოვიდა დედა-ჩემი მრავალ-ნაირი სანოვაგით, გაგვიხარდა რასაკვირველია. დედა მეუბნება: მითხრეს შენ მინისტრი ხარო, რავა დავიჯერო, ჩემი სარჩენი მინისტრი ვის გაუგონიაო!', '„ჩემი წარსული“, გვ. 102', ''),
  ('დათო ტურაშვილი', 'წარსულს თურმე დაბრუნებაც შეუძლია და განსაკუთრებით იმ შემთხვევაში, თუ იმ წარსულს ჩვენ თვითონაც არ ვშორდებით', 'ჯინსების თაობა', ''),
  ('დათო ტურაშვილი', 'საფლავი იყო ერთადერთი ადგილი საბჭოთა საქართველოში, სადაც საბჭოთა ხელისუფლება არ ვრცელდებოდა', 'ჯინსების თაობა', 'წარსული'),
  ('დათო ტურაშვილი', 'ოფიციალური იმედი არ არსებობს იმედი ერთია, ის შენია და შეგიძლია ამით იცოცხლო.', 'ჯინსების თაობა', ''),
  ('დათო ტურაშვილი', 'ქართველებმა კუბოს სასახლე დაარქვეს, რომ სიკვდილი მათთვის უფრო მსუბუქი ყოფილიყო.', 'ჯინსების თაობა', ''),
  ('დათო ტურაშვილი', 'თუ ადამიანი თუნდაც სხვების დასანახად მივა ეკლესიაში, მაინც უკეთესია, რადგან იქ უფრო მეტი დრო ექნება იმისათვის, რომ სიყვარულზე, ღმერთსა და ჭეშმარიტებაზე იფიქროს.', 'ჯინსების თაობა', ''),
  ('დათო ტურაშვილი', 'თქვენ არ იცით, როგორ ბოროტდებიან ამპარტავნები, როცა ისინი ხელისუფლებაში ხვდებიან.', 'ჯინსების თაობა', ''),
  ('დათო ტურაშვილი', '” -მაინც რატომ არ გეშინია არაფრის? – იმიტომ, რომ სიყვარულის არ მეშინია.“', 'ჯინსების თაობა', ''),
  ('დათო ტურაშვილი', 'იმედი სულ ბოლოს კი არა, საერთოდ არასოდეს კვდება.', 'ჯინსების თაობა', ''),
  ('დათო ტურაშვილი', 'იქ, სადაც ადამიანის სიკვდილი თოთხმეტი მანეთი ღირდა, ადამიანის სიცოცხლეს რა ფასი ექნებოდა.', 'ჯინსების თაობა', ''),
  ('მერაბ კოსტავა', 'მსოფლიო იცნობს ოცდაათწლიანი და ასწლიანი ომების ისტორიას, მაგრამ არსებობს მუდმივი, უვადო ომი. ეს საქართველოსი ისტორიაა.', 'მერაბ კოსტავა, მუზეუმების გაერთიანება, სტამბა სეზანი, 2019 წელი, ISBN-978-9941-8-1883-7 გვ. 21', ''),
  ('მერაბ კოსტავა', 'უნდა გიყვარდეს ეროვნული მოძრაობა და არა საკუთარი თავი ეროვნულ მოძრაობაში.', 'გვ. 22', ''),
  ('მერაბ კოსტავა', 'საქმეა იქცე მსოფლიო კაცად და არ უმუხთლო ერსა და თვისტომთ.', 'გვ. 196', ''),
  ('მერაბ კოსტავა', 'თუ ერთმანეთთან ვერ გამოვნახავთ სალაპარაკო ენას დღეს, შესაძლოა დადგეს დრო განუჭვრეტელი სიბნელისა, სადაც ჩვენ ერთმანეთს დაბრმავებული ვეძებდათ და ვეღარ ვპოვებდეთ', '', ''),
  ('ზვიად გამსახურდია', 'დიახ, წმინდანი იყო მუდამ იდეალი ჩვენი წინაპრების და ჩვენთვისაც უნდა დარჩეს იდეალად, თუ გვსურს ჩვენი ეროვნული და კულტურული არსებობის შენარჩუნება დღეს, ოკეანის პირისპირ, რომელიც ნთქავს ყოველგვარ ეროვნულ კოლორიტსა და ნიუანსებს. ის ერი კი, რომელიც დაკარგავს რწმენას და კულტურულ უპირატესობას ვერ შეინარჩუნებს მომხდურზე, უთუოდ დამარცხდება.', '„აირჩიე, ქართველო ერო“', ''),
  ('ზვიად გამსახურდია', 'თუ გსურს ერი, ან ადამიანი გახრწნა და გადააგვარო, მას არა მხოლოდ უნდა დაავიწყო წარსული, არამედ უნდა გაუყალბო კიდეც იგი. თავისი ჭეშმარიტი გმირები ბოროტმოქმედებად და უნიათო კაცუნებად უნდა დაუსახო, მედროვენი და მოღალატენი კი - გმირებად.', '„აირჩიე, ქართველო ერო“', ''),
  ('ზვიად გამსახურდია', 'არ შეიძლება საკუთარი თავისა და საკუთარი ხალხის მოტყუება - ამაზე მწარე ხვედრი, ამაზე შემზარავი დანაშაული არ არსებობს.', '„აირჩიე, ქართველო ერო“', ''),
  ('ზვიად გამსახურდია', 'პატარა შეცდომა ხშირად დიდი შეცდომის საწინდარია.', '„აირჩიე, ქართველო ერო“', ''),
  ('ზვიად გამსახურდია', 'ყველაფერი შეიძლება წაართვა პიროვნებას, ერს, მაგრამ ვერავინ შესძლებს თავისუფლების შეგრძნება წაართვას მას.', '„აირჩიე, ქართველო ერო“', 'თავისუფლება'),
  ('ზვიად გამსახურდია', 'დამოუკიდებლობა ხომ ერის ზნეობის გადარჩენაა და, ამდენად, თვით ერის გადარჩენაც.', '„აირჩიე, ქართველო ერო“', 'თავისუფლება, დამოუკიდებლობა'),
  ('ზვიად გამსახურდია', 'მტერს ეშინია ჩვენი ერთობისა.', '„აირჩიე, ქართველო ერო“', ''),
  ('ზვიად გამსახურდია', 'ნაცრად ქცეული ხე ისევე ხეს გამოადგებაო სასუქად. ცხოვრებაშიც ასეა: კაცმა რომ მეორე კაცს არგოს, ხესავით უნდა დაიწვას მისთვის და დანაცრდეს.', '„აირჩიე, ქართველო ერო“', ''),
  ('ზვიად გამსახურდია', 'როდესაც რაიმე დიდ საქმეს შეეწირება მსხვერპლად მისი მესვეური, ეს მოასწავებს ამ საქმის გამარჯვებას.', '„აირჩიე, ქართველო ერო“', ''),
  ('ზვიად გამსახურდია', 'რელიგიას გონებით, მარტო ინტელექტით ვერ გააცნობიერებ, ვერ გაიგებ, ყოველთვის გაწბილებული დარჩები.', '„აირჩიე, ქართველო ერო“', ''),
  ('ზვიად გამსახურდია', 'დღეს უწიგნური და უმეცარი ადამიანი ვერ იქნება ჭეშმარიტი მორწმუნე', '„აირჩიე, ქართველო ერო“', ''),
  ('ზვიად გამსახურდია', 'ეშმაკის მიერ ადამიანის შეცდენა გამოიხატა იმაში, რომ მან მისცა ინტელექტი, ამქვეყნიური ინტელექტი, ლოგიკა და ყველაფერი ის, რაც ღმერთს აშორებს ადამიანს.', '„აირჩიე, ქართველო ერო“', ''),
  ('გურამ დოჩანაშვილი', 'დაწოლისას, დაძინებამდე, არის ერთი, რაღაც პატარა, გარდამავალი წამი, როცა საკუთარი თავი ყველამ ვიცით.', 'სამოსელი პირველი', ''),
  ('გურამ დოჩანაშვილი', 'ნამდვილ ჯამბაზს თვალებში ყინული და წებო კი არა, ნაღვლიანი საიდუმლო უნდა ჰქონდეს...', 'სამოსელი პირველი', ''),
  ('გურამ დოჩანაშვილი', 'ძალიან დიდი განსხვავება არ აქვს იმას, ადრე მოკვდები თუ გვიან, რადგან ბოლო მაინც ეგ არის. მთავარია, თუ როგორ მოკვდები და რის ჩადენას მოასწრებ.', 'სამოსელი პირველი', ''),
  ('ივანე ჯავახიშვილი', 'ყოველ ჩვენგანს, მეტადრე მოხუცებულებს, უნდა ახსოვდეთ, რომ „იგი წავა და სხვა მოვა ტურფასა საბაღნაროსა“.', 'ივანე ჯავახიშვილის ცხოვრება და მეცნიერული ღვაწლი.', ''),
  ('დავით კვიცარიძე', 'ჩვენ ხომ სიკეთისთვის ვართ გაჩენილნი და ვეცადოთ. იქნებ მოხდეს სასწაული, იქნებ კეთილი გულით ნათქვამი არ აცდეს მიზანს,თესლი ნოყიერ ადგილას დავარდეს და იხეიროს.', '„ძეგლები მიწას არ ამძიმებენ“, გამომცემლობა „საბჭოთა საქართველო“, გვ. 5,', ''),
  ('დავით კვიცარიძე', 'თქვენს მეგობარს წამალზე უფრო მეტად ადამიანური სითბო სჭირდება.', '„ძეგლები მიწას არ ამძიმებენ“, გამომცემლობა „საბჭოთა საქართველო“, გვ. 210', ''),
  ('ნიკო ფიროსმანი', 'მე რომ ასი მანეთი მაინც მქონოდა, გამოვეწყობოდი კარგ ტანსაცმელში, დავიქირავებდი ოთახს, მაშინ კი ვხატავდი და ვხატავდი', '', ''),
  ('ნიკო ფიროსმანი', 'მოვა დრო და ჩემს ნახატებს მილიონებად გაყიდიან!', '', ''),
  ('ექვთიმე თაყაიშვილი', 'ვინც საქართველოს დამოუკიდებლობის მტერია, ის ჩვენი ყველას მტერია და ამათ უფლებას ვერ მივსცემთ ილაშქრონ ჩვენს წინააღმდეგ...ვინც ჩვენ დამოუკიდებლობას ძირს უთხრის, უსათუოდ მის წინააღმდეგ უნდა იქნეს ზომები მიღებული', '', 'დამოუკიდებლობა, თავისუფლება'),
  ('ეგნატე ნინოშვილი', 'გვიყვარდეს ერთმანეთი, ვირჩინოთ ჩვენი თავი ჩვენი შრომით და ვიყოთ. ნურვის ვაწყენთ და ჩვენც არავინ გვაწყენს.', '"სიმონა, გამომცემლობა ""განათლება"", თბილისი 1987"', ''),
  ('გიგა ბოკერია', 'ყველა ავტორიტარული რეჟიმის წინააღმდეგ მთავარი იარაღი მოქალაქეების ნდობაა', '', ''),
  ('დავით ჭიჭინაძე', 'გლეხს სწავლა რომ უყვარდეს, ის გლეხი არ იქნებოდა', '', ''),
  ('დავით ჭიჭინაძე', 'სწავლა რომ უყვარდეს, ის გლეხი არ იქნებოდა რა, დამიჯერეთ, სხვა ადგილს მიაგნებდა ამ ცხოვრებაში', '', ''),
  ('ლორიკ მარშანია', 'მე აფხაზი ვარ და ამაყად ვამბობ, რომ ჩემი საქართველო აფხაზეთიდან იწყება.', 'ლორიკ მარშანიას მიმართვა ვლადისლავ არძინბასადმი 1992 წლის სექტემბერი.', ''),
  ('დიმიტრი უზნაძე', 'სიკვდილის ფაქტი ყველას თანასწორ საშინელებას აღუძრავს არსებაში, ყველას თანაბარი შიშის თრთოლვით უქრობს იმედს და თუ ეს ასეა, მაშასადამე, იგი ფაქტობრივად ყველასთვის ერთგვარი სიდიდის ბოროტებას უნდა წარმოადგენდეს, ბოროტებას იმდენად აბსოლუტურს, რამდენადაც აბსოლუტურია მისგან გამოწვეული შიში.', '', ''),
  ('დიმიტრი უზნაძე', 'ცხადია, რომ ომიც ძირ-ფესვიანად ათავისუფლებს ჩვენს სულიერ ცხოვრებას გონების კატეგორიების ბატონობისაგან, და ამ გზით ჩვენს პირდაპირ უშუამავლო შეფასებას კვალს უკაფავს.', '', ''),
  ('დიმიტრი უზნაძე', 'ცხოვრების დანიშნულება, მისი აზრი და მიზანი სწორედ ამქვეყნად სიყვარულის სავსებითი განხორციელებაა. და თუ ეს ასეა, მაშ, ადამიანის ცხოვრებაც არაა გამონაკლისი. ამ შემთხვევაში მთელი ჩვენი ყოფნა-არსებობა სიყვარულის ან ერთობის და სოლიდარობის თანმიმდევარი განვითარების პირდაპირი გამოხატულებაა.', '', ''),
  ('ოთარ ჭილაძე', 'სიკვდილი ყველას შეუძლია, გადარჩენა კი – არა.', 'ყოველმან ჩემმან მპოვნელმან', ''),
  ('ჯემალ ქარჩხაძე', 'რაც უფრო მორიდებულია ადამიანი, მით უფრო ანტიმორიდებული ხდება, როცა კი მორცხვობას დაძლევს.', 'მდგმური', ''),
  ('ჯემალ ქარჩხაძე', 'შეიძლება ადრე მიყვარდა, მაგრამ ახლა მეცოდებოდა და, რაკი მეცოდებოდა, მაშასადამე არ მიყვარდა. შეუძლებელია, ქალი გიყვარდეს და თან გეცოდებოდეს. რადგანაც, სიყვარული, ალბათ, მუხლმოყრილი ლოცვაა, სიბრალული კი საკუთარი უპირატესობის შეგნება. ხოლო თუ ვინმეზე მუხლმოყრილი ლოცულობ, იქ უპირატესობის გრძნობა გამორიცხულია.', 'მდგმური', ''),
  ('ჯემალ ქარჩხაძე', 'ვინც ერთხელ სცადა თავის მოკვლა და ვერ მოიკლა, ის მეორედ აღარ ცდის.', 'მდგმური', ''),
  ('ჯემალ ქარჩხაძე', 'ოდიდგან ყველა მამაკაცს რომ გაეკეთებინა ის, რისი გაკეთებაც შეეძლო, დედამიწა აქამდე ან სამოთხედ იქცეოდა, ან ნამსხვრევებად.', 'მდგმური', ''),
  ('ჯემალ ქარჩხაძე', 'სამყაროს დასაბამიდან მამაკაცი ქმნის ყოველივეს. ავსაც და კარგსაც, შხამსაც და მალამოსაც, სიკვდილსაც და სიცოცხლესაც. ქალი კი ბიძგია. ხან ბიძგია, ხან შთაგონება, ხან საყრდენი.', 'მდგმური', ''),
  ('ჯემალ ქარჩხაძე', 'ყველა გენიალური აღმოჩენა მარტივია.', 'მდგმური', ''),
  ('ჯემალ ქარჩხაძე', 'ჭარბი სერიოზულობა სხვის თვალში ხშირად კომიკური ჩანს, არასერიოზულობა კი უფრო ეფექტური და მომგებიანია. განსაკუთრებით მაშინ, როცა ურთიერთობა გიხდება ლამაზ გოგოსთან და არა საქმიან ჩინოვნიკებთან.', 'მდგმური', ''),
  ('ჯემალ ქარჩხაძე', 'ადამიანის გამტყუნება ძნელია, მით უმეტეს, თუ შენ თვითონაც ადამიანი ხარ.', 'მდგმური', ''),
  ('ჯემალ ქარჩხაძე', 'სანამ განზრახვა მხოლოდ განზრახვაა, ყველაფერი იოლია. განზრახვის ნამდვილი ძალა და მნიშვნელობა მაშინ გამოჩნდება, როცა იგი ფაქტად იქცევა.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'პოპულარობა ავადმყოფური კმაყოფილებაა, რომელიც ღამღამობით, ძილისწინ, გამოფიტულობისა და სიცარიელის განცდას იწვევს და საკუთარ თავს გაძულებს.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'საერთოდ არაა ცნობილი, თუ სად, როდის და რატომ იბადება სიყვარული, რადგან კაცობრიობის ისტორიაში ჯერ არ გამოჩენილა ის ადამიანი, ვინც წარმატებულად დაშლის სიყვარულს შემადგენელ ნაწილებად და მის მექანიზმში გაერკვევა.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'ერთი შეხედვით სრულიად უმნიშვნელო შემთხვევას შეუძლია უღრმესი და თავდაუღწეველი სიყვარული დაბადოს. და საერთოდ, სიყვარული მუდამ ასეთ უბრალო და შეუმჩნეველ დეტალებზე აღმოცენდება ხოლმე.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'ცხოვრებას ასეთი წესი აქვს: ერთ ჭიქა შარბათს რომ შეგასმევს, მერე ერთ ჭიქა სამსალას მიგაყოლებინებს.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'დილით ფიცის დადება ადვილია, რადგან საღამო ჯერ არ დამდგარა.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'შეურაცხყოფის მიტევება სილაჩრე და სულმდაბლობაა, ხოლო შურისძიება ბოროტება, რომელიც წამსვე შეურაცხმყოფელის გვერდით მიგიჩენს ადგილს.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'ეს არის ცხოვრება. მთელი სიცოცხლე ლიანდაგზე მიდიხარ და წონასწორობის შენარჩუნებას ცდილობ. ხან ერთ მხარეს გადაგძლევს რაღაც ძალა, ხან მეორე მხარეს, ხანდახან ძლიერი ქარი დაუბერავს და რა მაგარი ბიჭიც არ უნდა იყო, მაინც გადაგაგდებს ლიანდაგიდან. მერე, ქარი რომ მიწყნარდება, ისევ ადიხარ და ისევ ცდილობ, წონასწორობა შეინარჩუნო. ხანაც ჩუმად მიიხედ-მოიხედავ და რომ დარწმუნდები, არავინ გიყურებს, სწრაფად გადმოხტები ლიანდაგიდან და ერთ მოზრდილ მონაკვეთს ასე გაივლი.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'კაცის ცხოვრებას ეპოქა განაპირობებს.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'ჩემი აზრით პროვინციალობა, ყოველ შემთხვევაში მისი ერთ-ერთი უმთავრესი ნიშანი, ისაა, კაცს რომ თავისი მოდელი ეთაკილება და სხვისი მოდელით ცდილობს იცხოვროს.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'იმისთვის, რომ საკუთარი თავი გადაგიხსნათ და შინ თქვენი თავი დაგანახვათ, უნდა გეთქვათ მადლობა. კაცი რომ ფარდას გადაგიწევს და წინ სარკედ დაგიდგება, ამით მსხვერპლს იღებს და ქრთამს თუ არა, მადლობას მაინც იმსახურებს.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'რუსთაველმა ცუდი სამსახური გაგვიწია, რადგან ძალიან დიდი ტილო გამოდგა და ყველას გვყოფნის ხელის შესაწმენდად. მერე რა, რომ ჩვენ არ ვვარგივართ?! სამაგიეროდ რუსთაველია დიდი. მერე რა, რომ ჩვენ უნიჭოები ვართ?! სამაგიეროდ რუსთაველია გენიოსი. მერე რა, რომ ჩვენ ასე დავკნინდით და დავბეჩავდით?! სამაგიეროდ რუსთაველია ამაღლებული.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'მდორე ადგილას მდინარეს მეტი სიღრმე აქვს, ვიდრე კლდე-ღრეებში, სადაც ყურისწამღებად მიხტუნავს.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'ჩვენ რუსთაველი იმისთვის გვინდა, რომ ვიამაყოთ. წაკითხვით კი არ ვკითხულობთ. წაკითხვით პოპულარულ ლაზღანდარაობებს ვკითხულობთ, რომლებიც საცრემლე ჯირკვლებს გვიღიზიანებენ, რათა თავი ჰუმანიზმისთვის წამებულად მოგვაჩვენონ. ჩვენ ყაჩაღებსა და წმინდანებს საერთო კვარცხლბეკზე ვუდგამთ ძეგლს, თევდორეები და ყორღანაშვილები ერთ საძმო სასაფლაოში გვიწევს. ამიტომ ჩვენი სახლი მყიფეა. ჩვენ ჩამსხვრეულ ფანჯრებში ქარი გადი-გადმოდის.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'პროგრესი მაშინ დაიწყება, როცა ჩვენს უვარგისობას შევიგნებთ... თუკი პროგრესი სულიერ და ზნეობრივ სფეროში საერთოდ შესაძლებელია.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'ადამიანის დანიშნულება ადამიანის გარეთაა საძებნელი. თუმცა თავისი თეორია ყველას შეიძლება ჰქონდეს. ჩემი თეორიის მიხედვით, ადამიანს არავიტარი დანიშნულება არ აქვს, უბრალოდ, სიცოცხლის იმპულსი აქვს, რომელიც გარდაუვალია და ამიტომ დანიშნულების ძიების სურვილს ბადებს.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'ყველა რომ ზნემაღალი იყოს, არავინ ლოთობდეს, ქუჩაში არავინ არწყევდეს, არავინ ქურდობდეს, არავინ ცრუობდეს, სიგარეტსაც კი არავინ ეწეოდეს და უკლებლივ ყველანი ზნეობისა და თავაზიანობის განსახიერებად ვიქცეთ, ხომ დაგვიდგა სამოთხე და ხომ მოკვდა ქალაქი მოწყენილობისგან.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'ჭეშმარიტი მსახიობი, ის, ვისაც მოწოდებით მსახიობს ვეძახით, დეზერტირია, რომელიც საკუთარ ტავს თვალს ვერ უსწორებს და ამიტომ ნიღბების ქვეყანაში გადადის საცხოვრებლად.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'ადამიანს აქვს ერთი ამოუძირკვავი თვისება, რომელიც ხან უძნელებს ცხოვრებას, ხან უიოლებს – მისი სიტყვა და საქმე შორიშორს დგანან ერთმანეთისგან. დედამიწის ზურგზე ჯერ კაცი არ დაბადებულა, რომელსაც მხოლოდ ის ეკეთებინოს, რასაც ფხიზელი გონება და საღი აზრი კარნახობდა.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'ჩვენი ხნის ერებმა საქმე დიდი ხანია მოათავეს. ჩვენ კი ისიც ვერ გავიგეთ, ჩვენი საქმე რა არის. საქართველო ისეთი ხომალდი გამოდგა, რომელშიც შემოქმედს საჭის ჩამონტაჟება დაავიწყდა.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'რამდენადაც სასიამოვნოა ყოველდღიური შეძენა და დახვავება, იმდენადვე გულდასაწყვეტი იქნება ბოლოს იმის განცდა, რომ თან ვერ წაიღებ.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'არსებობა ურთიერთობებია, არც მეტი, არც ნაკლები. გამოაცალე ადამიანს ურთიერთობები და ადამიანიც გაქრება. ჩვენ რომ გვგონია, თიტქოს ურთიერთობებში ადამიანის პიროვნება და ხასიათები მჟღავნდება, ტყუილია. თვითონ ადამიანი იქმნება ურთიერთობებში. ადამიანი ურთიერთობაა, მეტი არაფერი. ეს იმდენად ნათელი და ურყევი აქსიომაა, რომ მის ჭეშმარიტებაში ეჭვს ვერავინ შეიტანს სულის მეტი. სული კი რასაც გვეუბნებიან, თუ სიმართლეს გვეუბნებიან, სიცოცხლესა და სიკვდილს მიღმა დგას და, ამდენად, მატერიალური პასუხისმგებლობა არ აკისრია.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'როცა, ვთქვათ პურს თესავენ, ან სიმინდს, ნოყიერ ნიადაგზე კარგად ხარობს, მწირ ნიადაგზე - ცუდად. ადამიანიც ასეა: მწირ ეპოქაში თვითონაც მწირია და ნაკლებად ავლენს თავის შესაძლებლობებს. უკეთეს ეპოქაში უკეთ ავლენს.', 'ქარავანი', ''),
  ('ჯემალ ქარჩხაძე', 'სიცოცხლე იმად არა ღირს, მისი გულისთვის შიშს მონად გაუხდე.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ვისაც უკეთესი ბედი აქვს ის დიდ და ღონიერ სახელმწიფოში იბადება და თუ მაინცდამაინც მოიწადინებს, შეუძლია ნადირადაც იქცეს - ამით ქვეყანას ბევრი არა დააკლდება რა. ჩვენში კი ყოველი კაცი სათვალავშია ჩაგდებული. ჩვენში ყოველმა კაცმა საქართველო თავის ზურგით უნდა ზიდოს.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ქართველობა ჩვენი ხმალია და ქრისტიანობა ჩვენი ფარი. ვისთვისაც ღმერთს ფარისა და ხმლის მეტი არა მიუცია რა ის მეომარია და ძალიანაც რომ ეგულმძიმებოდეს უნდა იომოს. ჩვენი მიწა-წყალი მცირეა და გამუდმებული დარაჯობა სჭირდება. პატარა ქვეყანა დიდი სატკივარია. ჩვენი ქვეყანა კი იმდენად პატარაა ხელები რომ გაშალო თავ-ბოლოს მიწვდები. ასეთ ქვეყანას სხეულივით უნდა გრძნობდე და როცა შენს მიწაზე უცხო მოძალადე დადის ისე უნდა გტკიოდეს თითქოს შენს სხეულს თელავდეს.', '', ''),
  ('ჯემალ ქარჩხაძე', 'როდესაც კაცის არსებაში დიდება და სახელი შემოდის, იქიდან რამე უნდა განიდევნოს, რომ ადგილი იპოვოს, პირველ რიგში, იუმორის გრძნობა იდევნება ხოლმე.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ცოლი არასდროს აღიარებს ქმარს. ცოლი მედლის მეორე მხარეზე წერს ქმრის ბიოგრაფიას.', '', ''),
  ('ჯემალ ქარჩხაძე', 'იქნებ ჩვენ იმიტომ ვეწამებით, რომ სხვებს შვება მოვგვაროთ? იქნებ ადამიანის უმაღლესი დანიშნულება სწორედ ისაა, რომ მსხვერპლი იყოს?', '', ''),
  ('ჯემალ ქარჩხაძე', 'დიდება ქურქია. ქურქი გარედან გეხება და რამდენიც არ უნდა იწვალო, შენი სხეულის ნაწილად ვერ აქცევ.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ხოლო მე გეტყვი: ნუ გაიკეთებ ნიღაბს. ნუ დაკარგავ ღვთით მონიჭებულ სახეს.', '', ''),
  ('ჯემალ ქარჩხაძე', 'თეატრში იმის სანახავად მიდიხარ, რაც ცხოვრებაში გაკლია.', '', ''),
  ('ჯემალ ქარჩხაძე', 'სიმართლე რა ბედენაა შენიანის სისხლი თუ დაღვარე და მტრის საქმე აკეთე.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ზოგჯერ გამკლავებაზე მეტად გადარჩენაა საჭირო. ქართლი განა მიწაა! ქართლი ხალხია. ხალხი თუ აღარ იქნა, ცარიელ მიწას ხვალ ეგებ სპარსეთიც დაერქვას.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ქვეყანა განა ვაშლია, რომ პირდაპირ გულში გაუჩნდეს მატლი, როგორც კაცს უჩნდება! ქვეყანას მატლი გარედან ეხვევა და, როგორც კომბოსტოს, პირველად დიდ-დიდი ფურცლები ულპება, რომლებიც გამოსაჩენზეა.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ჩვენ გამუდმებით მოვდივართ ჩვენი წარსულიდან და ჩვენი წარსული მუდამ იქ არის, სადაც დავტოვეთ.', '', ''),
  ('ჯემალ ქარჩხაძე', 'არაფერი არ არსებობს ისე რეალურად, როგორც წარსული.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ნუთუ არ იცით, რომ ყოველი კაცის ცხოვრების ოთხმოცდაცხრამეტი პროცენტი წინამავალთა გამოცდილებაა? თეორიული მაქსიმუმი, რაც პიროვნული გენიისთვისაა დარჩენილი, არის ერთი პროცენტი და ვინც ამ ერთ პროცენტს გამოიყენებს, სწორედ ის არის გენიოსი.', '', ''),
  ('ჯემალ ქარჩხაძე', 'პოპულარობა ხომ დამოკიდებულია არა შემოქმედის ნიჭზე, არამედ მომხმარებლის გემოვნებაზე! ხოლო აქედან გამომდინარე პოპულარობა ისაა, რომ უარი თქვა საკუთარ გზაზე, შენი ნიჭი მომხმარებელთა საეჭვო გემოვნებას დაუმორჩილო და საკუთარ თავს უმტკიცო, რომ ვისაც მოსწონხარ, სწორედ მას აქვს მაღალი და დახვეწილი გემოვნება.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ჩვენ ყველანი ერთმანეთისგან შევდგებით და შეუმჩნევლად გადავდივართ ერთმანეთში. ამაში საკვირველი არაფერია. ვისაც ეს ხელს არ აძლევს, მან საკუთარი თავი უნდა უარყოს, რადგან თავისუფლება საკუთარი თავის უარყოფით იწყება. თვისებებზე უნდა თქვას უარი და, თუ ამის შემდეგ რაიმე დარჩა, იმას უნდა დაეპატრონო და მოუფრთხილდე, მაგრამ დარჩება რამე? აი, ეს არის საკითხავი.', '', ''),
  ('ჯემალ ქარჩხაძე', 'რელიგიას ერთი დიდი ნაკლი აქვს: ზედმეტად დემოკრატიულია. ამის გამო რელიგიაში ხშირად რწმენას კი არა თავშესაფარს პოულობენ, სადაც თავიანთ დაუკმაყოფილებელ პატივმოყვარეობას, უწიგნურობის კომპლექსს და ინტელექტის სიღარიბეს მალავენ.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ყოველ კაცს განვითარების საკუთარი, პიროვნული ბილიკი აქვს, რომელიც ერთ საერთო გზას უნდა უერთდებოდეს და თუ არ უერთდება, ეს ბილიკი გაუქმებული ბილიკია.', '', ''),
  ('ჯემალ ქარჩხაძე', 'სხეული ხელოვნური რამაა, სკაფანდრია, რომელიც სულს იმისთვის დასჭირდა, რომ დროსა და სივრცეს მორგებოდა და კონკრეტულ სამყაროში გამოვლენილიყო. სიცოცხლე და სიკვდილი სკაფანდრის არსებობის ფორმაა და არა სულის. სკაფანდრი გაცვდება და დაიშლება სული კიცქვიტად დაუბრუნდება თავის საწყისს, თავის წყაროს.', '', ''),
  ('ჯემალ ქარჩხაძე', 'სიმართლე შეგიძლია გვემო, ხაროში ჩააგდო და ზემოდან მიწა გადააფარო. ან არადა, ლაქი წაუსვა, ვერცხლის წყალში ამოავლო, ლამაზ ქათქათა ტყუილში გაახვიო, მაგრამ მოკვლით ვერ მოკლავ. სუნთქვას ვერ შეუკრავ. სიმართლის სუნთქვა მაინც გესმის, ცდილობ ყური არ ათხოვო და მაინც გესმის, როგორც საათის წიკწიკი სამარისებულ სიჩუმეში.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ჩვენ, ვინც პლასტილინისგან ვართ გამოძერწილი, ყოველ ნაბიჯზე ფეხით ვთელავთ ჩვენსავე სილამაზეს.', '', ''),
  ('ჯემალ ქარჩხაძე', 'სინამდვილეში ყველანი ბოღმითავართ სავსე. ამიტომ ვერ დავფრინავთ. ერთმშვენიერ დღეს რომ ყველა დარდმა, რაც ოთხი მილიარდი ადამიანის გულშია ჩაბუდებული, უეცრად რომ ამოხთქოს, ქვეყნიერება წაილეკება.', '', ''),
  ('ჯემალ ქარჩხაძე', 'გარეგნულად არავის ეტყობა რამე, თორემ ზოგი რახანია მკვდარია... სინამდვილეში ტვინის მუშაობა არაფერ შუაშია. კაცის სიცოცხლე სიყვარულია და სიძულვილი. და როცა სიყვარულიც გაქრება და სიძულვილიც, რა გაცხოველებითაც არ უნდა მუშაობდეს ტვინი, კაცი უკვე მკვდარია.', '', ''),
  ('ჯემალ ქარჩხაძე', 'მიზანი მაცდურია. სანამ მიაღწევთ, თქვენი გგონიათ; როცა მიაღწევთ, მაშინღა მიხვდებით, რომ სხვისი ყოფილა.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ჩვენ ილუზიურ სამყაროში ვცხოვრობთ. ილუზიურ სამყაროში ერთადერთი ჭეშმარიტება არის ოცნება. ჩვენ კი ოცნებას ცხვირსახოცად ვხმარობთ.', '', ''),
  ('ჯემალ ქარჩხაძე', 'ღმერთის პრობლემა საჭოჭმანო პრობლემაა, მაგრამ თუ მაინცდამაინც საბუთზე მიდგება საქმე, მისი არსებობის მთავარი დამადასტურებული საბუთი ისაა, რომ ის ყოვლისშემძლე არაა.', '', ''),
  ('კოტე მარჯანიშვილი', 'ხელოვნების მიზანი სულ უბრალოა — მიანიჭოს ადამიანს სიხარული, შთაბეროს მას მხნეობა.', '', ''),
  ('მამა გაბრიელი', 'შეიცან შენი უძლურება და უფალი გაგაძლიერებს შენ.', '', ''),
  ('მამა გაბრიელი', 'სიყვარული ლომს ქედს მოადრეკინებს', 'ბერის დიადემა გვ. 304', ''),
  ('მამა გაბრიელი', 'გული ვისგანაც მოგეცა, იმასვე ეკუთვნის.', 'ბერის დიადემა გვ.298', ''),
  ('მამა გაბრიელი', 'გულით სინანული მეტია ცრემლით სინანულზე.', 'ბერის დიადემა გვ.308', ''),
  ('მამა გაბრიელი', 'მოწყალება ოქროა, მოთმინება კი ბრილიანტი.', 'ბერის დიადემა გვ.309', ''),
  ('მამა გაბრიელი', 'სადაც მეტი მადლია, საჩუქარიც მეტი იქნება.', 'ბერის დიადემა გვ.311', ''),
  ('მამა გაბრიელი', 'მიწიერი ადამიანის გაღმერთება არ შეიძლება.', 'ბერის დიადემა გვ.303', ''),
  ('მამა გაბრიელი', 'ჯერ უგუნური უნდა იყო, რომ მერე ბრძენი გახდე.', 'ბერის დიადემა გვ.312', ''),
  ('მამა გაბრიელი', 'ყველა წესსა და კანონზე უპირატესი სიყვარულია.', 'ბერის დიადემა გვ.296', ''),
  ('მამა გაბრიელი', 'დიდი მადლია მტრედებს და ჩიტებს აჭამო საჭმელი.', 'ბერის დიადემა გვ.313', ''),
  ('მამა გაბრიელი', 'ცუდია, როცა ენა წინ გისწრებს, ჭკუა კი უკან გრჩება.', 'ბერის დიადემა გვ.305', ''),
  ('მამა გაბრიელი', 'ვინც ენასა და მუცელს სძლია, ის უკვე სწორ გზაზე დგას.', 'ბერის დიადემა გვ.299', ''),
  ('კახა ბენდუქიძე', 'თუ გლანძღავენ – ესე იგი საინტერესოდ ცხოვრობ, თუ გემუქრებიან – ესე იგი მათთვის საშიში ხარ, თუ ჯერ კიდევ ცოცხალი ხარ – ესე იგი მათ არ გაუმარჯვიათ!', '', ''),
  ('კახა ბენდუქიძე', 'ჩემი წარმოდგენა ჩემზე ძალიან განსხვავდება მათი წარმოდგენისგან ჩემზე, - მე ჩემი თავი უფრო ბუნჩულა მგონია, ვიდრე მათ ჰგონიათ რომ ვარ', '', ''),
  ('მერაბ მამარდაშვილი', 'ხომ შეიძლება, ღმერთი დაიღალოს აბსოლუტურად ბნელი ადამიანის გაშუქებით? აი, მაშინ კი, მაპატიეთ ეს გამოთქმა, ყოფა გეტირებათ.', '', ''),
  ('ირაკლი ჩარკვიანი', 'არავითარი განსხვავება არაა შენ იპარავ, თუ გასცემ, ყველაფერი ზედმეტისთვის ისჯები.', '', ''),
  ('ირაკლი ჩარკვიანი', 'ხელოვნება თავისი არსით უფრო ბედნიერია, ვიდრე უკვდავება.', '', ''),
  ('ირაკლი ჩარკვიანი', 'ადამიანების უმრავლესობას ხომ უბრალოდ მოთმინება არ ყოფნიდა მიეცა სიჩუმისთვის შანსი, შესაძლებლობა, საკუთარი თავი გამოევლინა, მიეღო ეს ღვთის საჩუქარი.', '', ''),
  ('ირაკლი ჩარკვიანი', 'ჭეშმარიტი გმირობა ხომ გმირობაზე უარის თქმაა.', '', ''),
