  ('ირაკლი ჩარკვიანი', 'ქალის ცრემლებზე უფრო მოსაწყენი, არაფერია ამქვეყნად.', '', ''),
  ('ირაკლი ჩარკვიანი', 'მკითხველი მინიმალურად უნდა დააბინძურო გამონაბოლქვით, არა აქვს მნიშვნელობა ეს მართლა ბენზინზე მომუშავე ძრავაა, თუ შენი სული.', '', ''),
  ('ირაკლი ჩარკვიანი', 'ჩემი გამოცდილებიდან გამომდინარე, შეცდომების გამოსწორება შეუძლებელია, ისინი რჩებიან ისტორიაში, ისევე როგორც მოპოვებული გამარჯვებები.', '', ''),
  ('ირაკლი ჩარკვიანი', 'იმედების დამყარება მშობლების საყვარელი გართობაა.', '', ''),
  ('ირაკლი ჩარკვიანი', 'მიენდე იმას რაც მოგეცა, მშვიდად ამოძრავე კიდურები, იცურე აუღელვებლად... სხეული ხომ ნავია... ხელები ნიჩბები... მოუსვი ისინი ისე რომ არ შეაწუხო შენს გვერდით მოცურავენი... ისინიც ეძებენ სწორ და ნეტარ რიტმს. ეცადე შეინარჩუნო მშვიდი ტემპი, არ შეანელო და არც ააჩქარო მოძრაობა... რომელიც თანდათან მუსიკასავით შთანთქავს მთელ შენ არსებას... მიყევი მას და გახსოვდეს, რომ შენი მელოდია განუმეორებელია, ყველაფერთან შესაბამისი და ჰარმონიული.', '', ''),
  ('ირაკლი ჩარკვიანი', 'სიყვარულს, სიხარულს არ ემუქრება სიბერე, როგორც სიმღერას ვერას აკლებს დრო.', '', ''),
  ('ირაკლი ჩარკვიანი', 'ჭეშმარიტ ხელოვნებას, როგორც წესი, ავტორი არ ყავს.', '', ''),
  ('ირაკლი ჩარკვიანი', 'რაც უფრო მეტს გასცემ, მით უფრო მეტი ადამიანი გტოვებს და რჩები ღმერთივით მარტო.', '', ''),
  ('ირაკლი ჩარკვიანი', 'ნუ უსმენ ხალხს!', '', ''),
  ('ირაკლი ჩარკვიანი', 'მე მოგცემ ძალას, მოერიო დაჟანგებულ ფრთებს', '', ''),
  ('ირაკლი ჩარკვიანი', 'დრო მხოლოდ სიყვარულს დაინდობს!..', '', ''),
  ('ირაკლი ჩარკვიანი', 'ფიქრებში ყოველთვის შენთან ვარ, შენი ვარ.', '', ''),
  ('ირაკლი ჩარკვიანი', 'მე ისევ მოვალ, ოღონდ არავის, არ გაუმხილო, რომ მე დავბრუნდი.', '', ''),
  ('ირაკლი ჩარკვიანი', 'რა გაქვს ჩემს სიყვარულზე მეტი?!', '', ''),
  ('ირაკლი ჩარკვიანი', 'არა, არ ღირან ეპოქები, რომ მათთან დარჩე!..', '', ''),
  ('ირაკლი ჩარკვიანი', 'ნუ დამიკარგავ იმედს, იმედს, რომ ხარ!..', '', ''),
  ('ირაკლი ჩარკვიანი', 'მე მხოლოდ შენს სიყვარულს ვგრძნობ, ყველაზე ღვთაებრივს და მართალს!..', '', ''),
  ('ირაკლი ჩარკვიანი', 'შენ ცხოვრობ; მე კი ვეღარ ვძლებ...', '', ''),
  ('ტარიელ ჭანტურია', 'ყველაფერი, რაც კლასიკოსის ხელიდანაა გამოსული, კლასიკა არ არის. როცა რომელიმე ჩვენგანი გაცხარებული ლანძღავს გალაკტიონის ზოგიერთ ლექსს, იგი გალაკტიონს არ ლანძღავს.', '', ''),
  ('მიხეილ ჯავახიშვილი', 'ჩვენ ჭუჭყი გარედან გვაცხია, ქალაქელს კი შიგნიდან აქვთ. სუ მუდამ იმას გონობენ, ვინ მოვატყუვავ, ჩვენ ჯაბსაღნი დომნი ორთ, თქვენ კი დამპალი ეშმანი ხართ და სულიც და ხორციც დამპალი გაქვთ.', 'თეთრი საყელო', ''),
  ('მიხეილ ჯავახიშვილი', 'მამაჩემი მიწას მოსწყდა და ქალაქს მიეკედლა. მეც მიწა ვიყავი და ისევ მიწას დაუბრუნდი.', 'თეთრი საყელო', ''),
  ('მიხეილ ჯავახიშვილი', 'წაწლობა — უზენაესი ძმური სიყვარულის მკაცრი ადათი - დღესაც არ ვიცი, ველური თუ ზეკაცური, ღვთიური თუ სატანური.', 'თეთრი საყელო', ''),
  ('მიხეილ ჯავახიშვილი', 'უცნაური სირცხვილის ჭია ჰღრნის უძღებ შვილს, რომელმაც თავისი ახალგაზრდობა და ძალ-ღონე სადღაც გაფლანგა და ეხლაღა მოიგონა ბებერი ძიძამიწა, რომელმაც აღზარდა და გამოკვება.', 'კვაჭი კვაჭანტირაძე', ''),
  ('მიხეილ ჯავახიშვილი', 'საქართველო მეტად პატარაა, რომ მე დამიტიოს.', 'კვაჭი კვაჭანტირაძე', ''),
  ('მიხეილ ჯავახიშვილი', 'რა ოხრად გინდა სიმართლე? მართლის თქმა ყველას შეუძლიან , - ტუტუცს, ველურს და ძუძუმწოვარსაც.', 'კვაჭი კვაჭანტირაძე', ''),
  ('მიხეილ ჯავახიშვილი', 'თქვენ ჯერ არ მიცნობთ, მე კვაჭი ვარ კვაჭანტირაძე, სილიბისტროს შვილი.', 'კვაჭი კვაჭანტირაძე', ''),
  ('მიხეილ ჯავახიშვილი', '- სულ ერთია ჩემო ბესო, პატიოსნებიდან არაფერი გამოდის. ირგვლივ ყველანი სძარცვავენ და იტაცებენ. - ძველებიც და ახლებიც. - პატიოსანი კაცი კი მშრალზე რჩება და მშიერი კვდება.', 'კვაჭი კვაჭანტირაძე', ''),
  ('მიხეილ ჯავახიშვილი', 'მონადირე ნადირს დასდევს. ნადირი კი მონადირეს თვითონვე წააწყდაო.', 'კვაჭი კვაჭანტირაძე', ''),
  ('მიხეილ ჯავახიშვილი', 'მინდა ერთხელ მაინც გავიგო შენგან მართალი სიტყვა. საცაა ჩამოგახრჩობენ, ეხლა მაინც ნუ ორპირობ.', 'კვაჭი კვაჭანტირაძე', ''),
  ('მამა გიორგი ბასილაძე', 'საქართველოს გაერთიანების და აღორძინების გასაღებს ტყუილა დაეძებს ბევრი ამერიკაში და ბევრიც რუსეთში! ეს გასაღები აქვე არის - საქართველოშიც, უფრო მეტიც - თითოეულ ქართველში! ეს აქ და „ზეციურ საქართველოში“ წყდება.', 'ქართველობა ძნელია, მაგრამ აუცილბელი!.. გვ. 143', ''),
  ('ამბროსი (კათოლიკოს-პატრიარქი)', 'სული ჩემი ღმერთს ეკუთვნის, გული ჩემი სამშობლოს, მძორი, ჯალათებო – თქვენ და რაც გინდათ ის უყავით მას.', '', ''),
  ('შალვა ნათელაშვილი', 'წამოვიდა მოსკოვიდან მილიონები თანამედროვე ორჯონიკიძეებზე. ღმერთმა არ გამოულიოს რუსეთს თარხან-მოურავის მსგავსი მოკავშირეები. მე მრცხვენია იმ ათლარიანი, გონება დაბნელებული არსებების მაგივრად, ვინც მათ დასტვენებზე დაიარება აქეთ-იქით.', '', 'პოლიტიკა'),
  ('შალვა ნათელაშვილი', 'ის პატარა ბიჭი რომ არის, არველაძე, გვარი არ მახსოვს…', '', 'პოლიტიკა'),
  ('შალვა ნათელაშვილი', 'ფეხბურთის ფედერაციის პრეზიდენტად მოიყვანეს გოგლი–მოგლით გასივებული ახალკაცი', '', 'პოლიტიკა'),
  ('შალვა ნათელაშვილი', 'დაუნ ვი დიქტეიტე!', '', 'პოლიტიკა'),
  ('მიხეილ სააკაშვილი', 'მე გპირდებით, რომ თქვენი სირცხვილის მიზეზი არასდროს ვიქნები.', '', 'პოლიტიკა'),
  ('მიხეილ სააკაშვილი', 'საქართველო არ არის უბრალოდ ევროპის ერთ-ერთი რიგითი ქვეყანა, ის ევროპის ერთ-ერთი ყველაზე ძველი ქვეყანაცაა.', '', 'პოლიტიკა'),
  ('მიხეილ სააკაშვილი', 'რა გგონიათ, დათვს რომ ბაბაის დაუძახებ, მოეწონები და აღარ შეგჭამს? დათვი უნდა გააგდო, დათვთან მოლაპარაკება შეუძლებელია. ხოლო როცა ის ადამიანური სახით მოგიბრუნდება, ადამიანს ყოველთვის უნდა ელაპარაკო.', '', 'პოლიტიკა'),
  ('მიხეილ სააკაშვილი', 'ბუბა კიკაბიძე მთელს მსოფლიოში საქართველოს სავიზიტო ბარათია', '', 'პოლიტიკა'),
  ('მიხეილ სააკაშვილი', 'ყველაზე მეტად გეშინოდეთ იმ ხალხის, ვინც იძახის, რომ არ აქვს პრეზიდენტად გახდომის უახლოესი გეგმები და უნდა იყოს ერთ-ერთი რიგითი ჯარისკაცი.', '', 'პოლიტიკა'),
  ('ვაჟა–ფშაველა', 'ადამიანი იმით ფასდება, აზრს ვინ ატარებს რამდნად ფრთიანსა.', '”საასპარეზოდ მოგვცა უფალმა”', ''),
  ('ვაჟა–ფშაველა', 'ადამიანის ფიქრის ერთი საქებული თვისება - მოვლენათა მიზეზების ძიებაა.', '”ფიქრები”', ''),
  ('ვაჟა–ფშაველა', 'ადამიანის გონება ყველას და ყველაფრის დაბერებას შეურიგდება, ხოლო სიბერე ერისა საშინელებაა.', '”ზოგი რამ ფიქრებიდან”', ''),
  ('ვაჟა–ფშაველა', 'ადვილ ვერ იცნობ ვაჟკაცსა მის ვაჟკაცური რჯულითა', '”ალუდა ქეთელაური”', ''),
  ('ვაჟა–ფშაველა', 'ავი დატანჯე და დაამონე, კეთილის მქნელსა შეასხი ფრთები.', '„სვინიდისი“', ''),
  ('ვაჟა–ფშაველა', 'ავი კაცის პურ-მარილიც მოსარიდებელია და ცნობა-მეგობრობაც.', '„თიანეთური ფელეტონი“', ''),
  ('ვაჟა–ფშაველა', 'ავსა და კარგსა კაცისას როდი ივიწყებს სოფელი.', '„საახალწლო“', ''),
  ('ვაჟა–ფშაველა', 'აზრი სწორი და შრომა მედგარი, ბედნიერების მოსაპოვებლად ერთი სახსარი მხოლოდ ეგ არი.', '„წვეთი და ლოდი“', ''),
  ('ვაჟა–ფშაველა', 'აზრის წარმოთქმა რომელიმე საგანზე თვით საგნის შეუსწავლელად და შეუგნებლად მხოლოდ რეგვენ ადამიანს შეუძლია.', '„ცოტა რამ ჩვენი ცხოვრების ავ კარგისა“', ''),
  ('ვაჟა–ფშაველა', 'ათი ათას სჯობს მტრედს, კაკაბს, მარტო არწივის თვალები.', '„მთათა ერთობა“', ''),
  ('ვაჟა–ფშაველა', 'ათისა და ოცის კაცის ავაზაკობა ისე ვერ დააზიანებს ერის ცხოვრებას, როგორც სხვაგვარი ავაზაკობა ათასისა და ორი ათასისა, - პირველთ ადვილად ვიშორებთ თავიდან, ავაზაკებს ვეძახით, ვსდევნით, როგორც ცოფიან ძაღლებს, ვეტევებით თოფით და ხმლით, მოსაკლავად არა ვზოგავთ, ხოლო მეორე ჯულის ავაზაკებს ვძმობილობთ და ვემოყვრებით.', '„თიანეთური ფელეტონი“', ''),
  ('ვაჟა–ფშაველა', 'ან უსამშობლომ, კაცმა ბოგანომ, რა იცის, რაა სამშობლოს ტრფობა?!', '„საასპარეზოდ მოგვცა უფალმა“', ''),
  ('ვაჟა–ფშაველა', 'არ ვარგა ერთურთიკილვა, უგზოდ სიტყვების რახუნი.', '„საახალწლო“', ''),
  ('ვაჟა–ფშაველა', 'არ ესმის სხვისა ტკივილი სხვასაო.', '„გამამერია ჭაღარა“', ''),
  ('ვაჟა–ფშაველა', 'არ მგონია შეედრებოდეს ერთი საგანი მეორეს ისე, როგორც მდინარე და ენა. რით ჰგავს ენა მდინარეს? იმითი, რომ რაც ერთხელ მდინარეს გემო და თვისება მიუღია, თუ ხელოვნულად არ მოსტაცე, არ წაართვი, იგი თავისთავად არასოდეს არ დაჰკარგავს, მიმდინარეობას იმ ჟამით ჟამამდე დაუდგრომელად, მისი შეჩერება, დაგეუბება ცოტა ხნობით თუ შეიძლება, ხოლო სამუდამოდ კი არასოდეს.', '', ''),
  ('ვაჟა–ფშაველა', 'არა მოგცა რა ლამაზის სიტყვებით ამაყობამა.', '„ქებათა-ქება“', ''),
  ('ვაჟა–ფშაველა', 'ბავშვი მანამ მოლაშქრეობას შეძლებს, ჯერ ყბედობს და სახელიც მაშინ ერქმევა.', '„გაზვიადებული საკითხავი“', ''),
  ('ვაჟა–ფშაველა', 'თავის მარცხს კაცნი ვერ ვიტყვით, ჩქარა ვიუბნებთ სხვისასა.', 'ლიტ.ფიქრები. ვაჟა-ფშაველას აფორიზმები და გამონათქვამები, შემდგენელი მ.მთვარელიძე. თბილისი, 1988.', ''),
  ('ვაჟა–ფშაველა', 'სამშობლოს არვის წავართმევთ, სხვაც ნურვინ შეგვეცილება, თორემ ისეთ დღეს დავაყრით მკვდარასაც კი გაეცინება.', '', ''),
  ('ვაჟა–ფშაველა', 'მხოლოდ იმაში არ გამოიხატება თავისუფლება, რაც გნებავს ის ილაპარაკო, სწერო, აკეთო, – არა! უნდა ყოველს სიტყვას და მოქმედებას საერთო, საზოგადო ბედნიერება ედვას სარჩულად, ქვეყნის თუ სასარგებლო არა, სამავნებლო, საზარალო მაინც არ უნდა იყოს ქვეყნისათვის.', '', ''),
  ('ვაჟა–ფშაველა', 'ახ რა ცუდია, რა ცუდი, გზაარეულად მსჯელობა, ცეცხლმოდებულის ერისა თავისი თავის მტერობა!', '', ''),
  ('ვაჟა–ფშაველა', 'ბედნიერი მაშინ ვარ, რომ ვიტანჯვი სხვისთვისა.', '', ''),
  ('ვაჟა–ფშაველა', 'ბევრად სჯობია სიკვდილი, მშობელი დედის წყენასა.', '', ''),
  ('ვაჟა–ფშაველა', 'არ მინდა თავს ლეშად ვგრძნობდე, უსულოდ გდებულს ტიალად.', '', ''),
  ('ვაჟა–ფშაველა', 'არც ის მგონია ბიჭობა, ვისაც ერევი ახრჩობდე, ბიჭს მაშინ დაგიძახებდი, რომ სხვას დამხრჩვალსა სწამლობდე.', '', ''),
  ('მიხეილ ჯავახიშვილი', 'დრო არასოდეს არ მოდის, იგი მიდის და ვინც მას არ გაჰყვება, დაიღუპება.', '', ''),
  ('მიხეილ ჯავახიშვილი', 'საკუთარი თავის დამცირება ამპარტავნობაზე უარესია.', '', ''),
  ('მიხეილ ჯავახიშვილი', 'ადამიანი ერთსა და იმავე ალაგას მეორეჯერ აღარ წაიქცევა, მაგრამ სამაგიეროდ, ყოველი ნაბიჯი წასაქცევი ალაგია და ამიტომ ნურავინაც ნუ დაიფიცებს ამას იქით აღარ წავიქცევიო.', '', ''),
  ('მიხეილ ჯავახიშვილი', 'ადამიანის დასამარებისათვის ორი ხერხი არსებობს. პირველი - დუმილი, მეორე - გამომჟღავნება. მე გამოვთქვი აზრი, რომ შეიძლება დუმილი სჯობდეს.', '', ''),
  ('ოთარ ჭილაძე', 'ქალს რამეზე ხელი რომ ააღებინო, სამაგიეროს უნდა დაჰპირდე, თან უკეთესს.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'უბედურებაში ჩავარდნილ კაცს ყველაზე მეტად თანაგრძნობა სჭირდება, თუნდაც მოჩვენებითი, ყალბი, მოვალეობის მოსახდელი.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'უბედურებაზე უფრო, მარტო დარჩენის ეშინია კაცს.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ტკივილი და სიბრაზე ადამიანს უფრო გულახდილს ხდის, უფრო გულწრფელს, ვიდრე მერეა, როცა სიბრაზე გადაუვლის და ტკივილიც ჩაუწყნარდება.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'როცა ანგარებაა გარეული საქმეში, გინდა ერთ კაცს დაუწექი და გინდა მთელ ქალაქს, მაინც მეძავი ხარ, რადგან სხეულს ყიდი და არავითარი მნიშვნელობა არა აქვს, ერთი მუშტარი გყავს თუ ათასი, ფულს გიხდიან თუ ერბოს.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'კაცს ქალი რყვნის.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ცხოვრება გაწბილებული ოცნებაა, საწინააღმდეგოდ ამხდარი სიზმარია, ლამაზი, ყურის მაამებელი, გულის გამკეთებელი სიტყვა კი არაა, არამედ ამ ლამაზი სიტყვებიდან დაბადებული მკაცრი და დაუნდობელი სიმართლე.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'რაც არ ეგუება – კვდება.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ვაჟკაცობა თავის გამოდება და სიკვდილი კი არა, გადარჩენაა, რადაც არ უნდა დაგიჯდეს ის.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'მწერზე მეტი განსჯის უნარი არც ადამიანს გააჩნია, სადაც შუქი აინთება, ყველა მისი გულისთვის, მის მისაზიდად და მის გასართობად ჰგონია ანთებული.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ადამიანი მხოლოდ სიცოცხლე ან მხოლოდ სიკვდილი კი არ არის, არამედ ორივე ერთად, სიკვდილიცა და სიცოცხლეც, სიკვდილ-სიცოცხლე, ერთი მეორეს ქმნის, ორივე ერთად კი – ადამიანს.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ბედი არსებობს იმდენად, რამდენადაც ადამიანს სჭირდება მისი არსებობა, თუნდაც მხოლოდ იმიტომ, მას რომ გადააბრალოს თავისი მარცხიცა და წარმატებაც და ამით უფრო ასატანი გახადოს საკუთარი არსებობა მეორე ადამიანისთვის.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ადამიანი მარტო არასოდეს არ არის, მარტო თავის თავს არასოდეს ეკუთვნის.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'მიჩვეულს ნუ გადააჩვევ და მიუჩვეველს ნუ მიაჩვევ, ამაშია ადამიანის ბუნების მთელი საიდუმლო.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ადამიანის სიცოცხლესაც და სიკვდილსაც არა თვითონ ადამიანი, არამედ უხილავი სული ქმნის და ადამიანი უმწეოა, იღონოს რამე.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ბავშვობა მხოლოდ მაშინ აჩენს სინანულის გრძნობას, როცა კარგა ხნის დამთავრებულია იგი.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ერთადერთი გზა შეგუებაა, დანარჩენი თავისით მოვა.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'მოწყალების მიღება საკუთარი უმწეობის აღიარებაა, ხოლო მოწყალების გაღება საკუთარი უპირატესობის დასამტკიცებლად სჭირდება ადამიანს.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ამ ქვეყანაზე ტყუილად არავინ არაფერს იძლევა, მაგრამ ძლიერია არა ის, ვინც იძლევა, არამედ ის, ვინც არ იღებს.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'გაუზიარებელი ბედნიერება გაზიარებულ უბედურებაზე მწარეა.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'სიმახინჯისაკენ მიდრეკილება ადამიანის ერთ-ერთი მთავარი თვისებაა, რადგან სიმახინჯე სილამაზის ხვალინდელი დღეა, უფრო მშვიდი და ხანგრძლივი.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'კაცობრიობის ერთიანობას ერთ ქარგაზე მოჭრილი ნიფხავი კი არ განაპირობებს, არამედ დიადისკენ ერთნაირი მიდრეკილება, შექმნის მოთხოვნილება და უნარი.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ადამიანისთვის ნამდვილი ის არის, რასაც ეჩვევა ყოველდღიურად, თანდათანობით და სამუდამოდ.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ადამიანი მხოლოდ მაშინ ითვლება მკვდრად, როცა იმის სიკვდილს შეეგუებიან.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'გაუმართლებელი, გადამეტებული სიკეთე ბოროტებას აღვივებს მხოლოდ.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ადამიანი იმას კი არ ირჩევს, რაც მას უნდა, არამედ, იმას თანხმდება, რასაც თავზე ახვევენ… ანდა იღუპება.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'იმედის ანაბარა ცხოვრებას უიმედო ბრძოლა სჯობია.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'თანაგრძნობა მხოლოდ იმისგან შეიძლება მიიღო, ვისაც შენს უბედურებასთან არაფერი ესაქმება, ვისი ხელიც არ ურევა შენს უბედურებაში.', '"""ყოველმან ჩემმან მპოვნელმან“"', ''),
  ('ოთარ ჭილაძე', 'ადამიანი სინდისია. სინდისის გარდა, რაც არ უნდა წაართვა, მაინც ადამიანი იქნება. მაგრამ სინდისი რომ წაართვა და სხვა ყველაფერი დაუტოვო, ვეღარ იქნება ადამიანი.', '"""მარტის მამალი"""', ''),
  ('ოთარ ჭილაძე', 'სინდისი იგივე სულია ადამიანისა, ანუ, სული იგივე სინდისია.', '"""მარტის მამალი"""', ''),
  ('ოთარ ჭილაძე', 'ვიდრე ადამიანს სინდისი აწუხებს, ყველაფერს ეშველება კიდევ, რადგან მთვარი ის კი არ არის, ღმერთმა ტალახისგან რომ შექმნა ის, არამედ, მთავარია, თავისი სული რომ ჩაჰბერა იმ ტალახს.', '"""მარტის მამალი"""', ''),
  ('ოთარ ჭილაძე', 'ადამიანის ფიქრი და ოცნება მოითხოვს სივრცეს და არა თავად ადამიანი.', '"""მარტის მამალი"""', ''),
  ('ოთარ ჭილაძე', 'რაც გიყვარს, სიყვარულის გამო უნდა გიყვარდეს მხოლოდ და რაც გძულს, ისიც სიყვარულის გამო უნდა გძულდეს.', '"""მარტის მამალი"""', ''),
  ('ოთარ ჭილაძე', 'ადამიანი ძალაუფლების მაძიებელი ცხოველია.', '"""გოდორი"""', ''),
  ('ოთარ ჭილაძე', 'უსაფუძვლო სიძულვილი და ბრმა რწმენა აიძულებს ახალგაზრდას ქუჩაში გამოვიდეს და ხელი მოუღეროს ხელისუფალს.', '"""გოდორი"""', ''),
  ('ოთარ ჭილაძე', 'თუკი ხელისუფლების შენარჩუნება გსურს, პირველ რიგში, შეკითხვის გეშინოდეთ, ბავშვის პირიდან ამოსულის.', '"""გოდორი"""', ''),
  ('ოთარ ჭილაძე', 'ბავშვი საზარელი იარაღია, თუკი არადანიშნულებისამებრ გამოიყენებ.', '"""გოდორი"""', ''),
  ('ოთარ ჭილაძე', 'ვიდრე ბუნების ენას არ ვისწავლით, ყველა ცოდნა დამღუპველია.', '"""გოდორი"""', ''),
  ('ოთარ ჭილაძე', 'ყველა ჭეშმარიტი პოეტი ან მკვდარია, ან უგულებელყოფილი. ვინც იბეჭდება, ხელისუფლებას ემსახურება, რადგან ნებისმიერი ხელისუფლება მხოლოდ იმის დაბეჭვდის უფლებას იძლევა, რისი დაბეჭდვაც უპირველეს ყოვლისა თვისთვის მიაჩნია სასარგებლოდ და არა პოეტისთვის.', '"""გოდორი"""', ''),
  ('ოთარ ჭილაძე', 'თავის მოსულელებაც ერთგვარი სახეა ბრძოლისა, მით უფრო, როცა სხვა აღარაფერი შეგიძლია.', '"""გოდორი"""', ''),
  ('ოთარ ჭილაძე', 'საქართველოში, ქართველის გარდა, ჯერჯერობით არავინ დაჩაგრულა.', '"""გოდორი"""', ''),
  ('ოთარ ჭილაძე', 'ადამიანი არასოდეს მარტო არ ცდება, მაგრამ, სამწუხაროდ, ყოველთვის მარტო აგებს პასუხს საერთო შეცდომებისთვის.', '"""გოდორი"""', ''),
  ('ოთარ ჭილაძე', 'კაცი ძველ ტანსაცმელს საჭიროებისათვის იცვამს, ახალს კი თავის გამოსაჩენად და სხვების გულის გასახეთქადო.', '"""გოდორი"""', ''),
  ('ილია ჭავჭავაძე', 'კაცი მარტო მაშინ არის ხერხი, როცა ცოდნა აქვს, როცა ჭკუა ცოდნით გაულესია, ცოდნის ჩარხზე გაუჩარხავს. მაშინ ხერხსავით სხვისთვისაც გააქვს და თავისთვისაც შემოაქვს.', '', ''),
  ('ილია ჭავჭავაძე', 'ადამიანის უძვირფასესი საუნჯე მისი ვინაობაა.', '', ''),
  ('ილია ჭავჭავაძე', 'ავი კაცი რამდენადაც მეცნიერია, დიდი სწავლული, იმოდენად უფრო ძლიერ საშიშია, უფრო ძლიერ მავნებელია.', '', ''),
  ('ილია ჭავჭავაძე', 'არამც თუ უსაბუთო ძაგება, უსაბუთო ქებაც კი საწყენია მართებულის კაცისათვის.', '', ''),
  ('ილია ჭავჭავაძე', 'ზოგი საგანია, რომ თუ არ დაინახავ, ვერ ირწმუნებ, და ზოგი - იმისთანა, თუ არ ირწმუნებ, ვერ დაინახავ.', '', ''),
  ('ილია ჭავჭავაძე', 'მხოლოდ წარსულის ცოდნით დაუცავს ყოველს ერს თავისი ეროვნება, თავისი არსებობა, თავისი ვინაობა.', '', ''),
  ('ილია ჭავჭავაძე', 'ვინც კარგად ემსახურება სამშობლო ქვეყანას, იგი უდიდგვაროდაც დიდია.', '', ''),
  ('ილია ჭავჭავაძე', 'აწმყოს, რომელსაც წარსული არ აქვს, არც მომავალი აქვს.', '', ''),
  ('ილია ჭავჭავაძე', 'ქვეყანა ტაძარი კი არაა, საცა კაცი უნდა ლოცულობდეს, არამედ სახელოსნოა, საცა უნდა ირჯებოდეს და მუშაობდეს!', '', ''),
  ('ილია ჭავჭავაძე', 'ადამიანის გული თვალუწვდენელი ორმოა.', '', ''),
  ('ილია ჭავჭავაძე', 'გახსოვდეს, რომ ქვეყანაზე ქაღალდის გარდა არის კიდევ სინდისი.', '', ''),
  ('ილია ჭავჭავაძე', 'ბედს თვითონ კაცი ქმნის და არა ბედი კაცსა.', '', ''),
  ('ილია ჭავჭავაძე', 'ქვეყანაზე, რომ ჭირი არ იყოს, ადამიანი ენასაც არ ამოიდგამდა.', '', ''),
  ('ილია ჭავჭავაძე', 'ჭეშმარიტ ღირსებას ყვირილი არ უნდა.', '', ''),
  ('ილია ჭავჭავაძე', 'დიდი სიბრძნეა კაცისა, ცნობა თავისი თავისა.', '', ''),
  ('ილია ჭავჭავაძე', 'ქვეყნის სამსახური ყველგან მსხვერპლია და არა სეირი.', '', ''),
  ('ილია ჭავჭავაძე', 'მეზობლის უბედურებაზე ჩვენი ბედნიერება ვერ დაფუძნდება.', '', ''),
  ('ილია ჭავჭავაძე', 'ღობე-ყორეს მოდება ღალატია საქმისა.', '', ''),
  ('ილია ჭავჭავაძე', 'ხშირია ხოლმე, რომ, როცა სული ჭლქედება, ხორცის დღეობა მაშინ არის; როცა სული ჰყვავის, ხორცი დნება.', '', ''),
  ('ილია ჭავჭავაძე', 'იგი გრძნობაა მართალი, რომელიც კატასავით დღე მუდამ არა სჩხავის და მზეთუნახავად დაბინავებულა გულში.', '', ''),
  ('ილია ჭავჭავაძე', 'თუ სახელის შოვნა გინდა, დღეს ისეთი ნერგი დარგე, რომ ხვალემა მადლობით სთქვას: „ნანერგითა შენითა მარგე“.', '', ''),
  ('ილია ჭავჭავაძე', 'პატარა ნიჩბითაც ბევრი რამ გაკეთდება და ძალიან შესაძლოა ცოტ-ცოტაობიდან დიდი საქმე გამოვიდეს.', '', ''),
  ('ილია ჭავჭავაძე', 'რასაც თვითონ არ ვიმოქმედებთო, სხვისგან ბევრს ნურას ველოდებითო.', '', ''),
  ('ილია ჭავჭავაძე', 'კმაყოფილება კაცის მომაკვდინებელი სენია.', '', ''),
  ('ილია ჭავჭავაძე', 'ქვეყანა იმით კი არ არის უბედური, რომ ღარიბია, არამედ იმით, რომ მცოდნე, გონებაგახსნილი, გულანთებული კაცები არა ჰყავს.', '', ''),
  ('ილია ჭავჭავაძე', 'შენ რომ ცუდკაცობდე, კაიკაცობაზედ სხვას მაინც ნუ გალანძღავ.', '', ''),
  ('ილია ჭავჭავაძე', 'წარსული მკვიდრი საძირკველია აწმყოსი, როგორც აწმყო მომავლისა.', '', ''),
  ('ილია ჭავჭავაძე', 'ვინც კაცად არ ვარგა, ის არც მამად ივარგებს, არც დედად და არც სხვად რადმე; იმიტომ, რომ მამობა და დედობა ადამიანური მარტო შვილების გამრავლება და ძუძუს წოვება არ არის.', '', ''),
  ('ილია ჭავჭავაძე', 'ვინც ლაფში თავიდან ფეხებამდე ამოსვრილია, არ შეიძლება ისე შეეხოს სხვას, რომ თავისი ლაფი იმასაც არ მოაცხოს.', '', ''),
  ('ილია ჭავჭავაძე', 'ერი, ერთის ღვაწლის დამდები, ერთს ისტორიულ უღელში ბმული, ერთად მებრძოლი ერთსა და იმავე ჭირსა და ლხინში გამოტარებული – ერთსულოვნებით, ერთგულებით ძლიერია.', '', ''),
  ('ილია ჭავჭავაძე', 'თუ სათავე მღვრიეა, ბოლოში ამაო იქნება წმინდა წყლის ძებნა.', '', ''),
  ('ილია ჭავჭავაძე', 'კარგია გაღვიძებული ადამიანი, მაგრამ უფრო უკეთესია ადამიანი, რომელსაც ძილშიაც არა სძინავს, ქვეყნის უბედურებით გულ-აღტკინებულსა.', '', ''),
  ('ილია ჭავჭავაძე', 'ლუკმა მაშინ არის ტკბილი, როცა კაი კაცობით არის ნაშოვნი.', '', ''),
  ('ილია ჭავჭავაძე', 'მარტო შენი მტერი დაგიმალავს, შენს სახეზედ რომ ურიგობა ჰნახოს რამე, მოყვარე კი მაშინვე სარკეს მოგიტანს, რომ გაისწორო და ხალხში არ შერცხვე.', '', ''),
  ('ილია ჭავჭავაძე', 'სხვა შენთვის და შენ სხვისთვის, აი გზა ცხოვრებისა.', '', ''),
  ('ილია ჭავჭავაძე', 'ჩემი მსაჯული ჩემი ტვინია და ის პატარა ღმერთი, რომელსაც სინდისს ეძახიან.', '', ''),
  ('ილია ჭავჭავაძე', 'ხვალე არ უნდა ჰგავდეს დღევანდელს, თუ კაცს პროგრესი, წინსვლა ადამიანისა ფუჭ სიტყვად არ მიაჩნია.', '', ''),
  ('ილია ჭავჭავაძე', 'ხელი მიეც შენს მეზობელს, შეერთდით, ერთად იმუშავეთ, თუ გინდათ ქვეყანაში რიგიანად იცხოვროთ.', '', ''),
  ('ილია ჭავჭავაძე', 'ის იცინის კარგად, ვინც ბოლოს გაიცინებსო.', '', ''),
  ('ილია ჭავჭავაძე', 'ფეხს ვერ გასძრავთ, თუ საკუთარის ტვინის ძაფები არ ამოქმედეთ, თუ საკუთარი გრძნობა და ჭკუა არ წაიმძღვარეთ, თუ საკუთარი მსჯელობა არ იქონიეთ.', '', ''),
  ('ილია ჭავჭავაძე', 'ზოგჯერ მოკლე სიტყვაც გრძელია.', '', ''),
  ('ილია ჭავჭავაძე', 'დედაც კაცია, – გვეუბნება ჩვენი ენა, – და მამაცაო.', '', ''),
  ('ილია ჭავჭავაძე', 'ათი-ათასჯერ არაფერი მაინც არაფერია.', '', ''),
  ('ილია ჭავჭავაძე', 'ბოდიში ძნელად თუ მოარჩენს მოგრეხილს კისერსა, – და არც მოტეხილი ფეხისთვის არის უებარი წამალი.', '', ''),
  ('ილია ჭავჭავაძე', 'ვინც თვითონ მოიპოვებს სახელს, იგი ბევრით წინ არის იმაზე, ვისაც სახელი მამა-პაპათაგან რჩენია და რგებია.', '', ''),
  ('ილია ჭავჭავაძე', 'თავისუფლების შოვნაი სჯობს საშოვნელსა ყველასა.', '', ''),
  ('ილია ჭავჭავაძე', 'კაცად მაშინ ხარ საქები, თუ ეს წესი წესად დარგე: ყოველ დღესა შენს თავს ჰკითხო, – აბა დღეს მე ვის რა ვარგე?', '', ''),
  ('ილია ჭავჭავაძე', 'სიკეთით სძლიე შენს მტერსა, ერიდე სისხლით ზღვევასა: სულგრძელობითა ძლევა სჯობს ვაჟკაცობითა ძლევასა.', '', ''),
  ('ილია ჭავჭავაძე', 'სიტყვა თქმაა და არა ქმნა. თქმასა და ქმნას შორის დიდი ზღვარია.', '', ''),
  ('ილია ჭავჭავაძე', 'რაც გინდა პატარა იყოს სამშობლო ქვეყანა, – პატიოსანს გულში დიდი ადგილი უჭირავს.', '', ''),
  ('ილია ჭავჭავაძე', 'ღონიერი და ჭირთა მძლევი ის არის, ვისაც ჭკუა ცოდნით მოურთავს, ცოდნით აუყვავებია, ცოდნის ძუძუთი გაუზრდია.', '', ''),
  ('ილია ჭავჭავაძე', 'ხეს ვერ გაზრდი იმ დროზე ადრე, რაც ბუნებას დაუნიშნავს.', '', ''),
  ('ილია ჭავჭავაძე', 'ხმალი მაშინ უფრო კარგია, როცა ის ფარია და არა სატევარი.', '', ''),
  ('ილია ჭავჭავაძე', 'ერთი „მაქვს“ სჯობს ათას „გქონდა-ს“.', '', ''),
  ('ილია ჭავჭავაძე', 'პატიოსანთ მტერთა შორის მოციქული ნამუსია.', '', ''),
  ('ილია ჭავჭავაძე', 'ყველა კაცმა რომ იგი სიკეთე ჰქმნას, რის შემძლებიც არის, ქვეყნიერებაზე უბედურნი აღარ იქნებიან.', '', ''),
  ('ილია ჭავჭავაძე', 'უფულო ერი ერთა შორის და უფულო კაცი ადამიანთა შორის ყმაა ფულიანისა.', '', ''),
  ('ილია ჭავჭავაძე', 'ფული რამდენადაც ბევრია, იმოდენადაც ხარბია და გაუმაძღარი.', '', ''),
  ('ილია ჭავჭავაძე', 'მეზობლის უბედურებაზე ჩვენი ბედნიერება ვერ დაფუძვნდება, ვერ აშენდება.', '', ''),
  ('ილია ჭავჭავაძე', 'ქართველს კაცს არც ქარის შემოტანილი უნდა არც გატანილი.', '', ''),
  ('ილია ჭავჭავაძე', 'დამალული ჭირი ძნელია, პირდაპირ მოსულს კიდევ როგორც იქნება შეეჭიდება კაცი.', '', ''),
  ('ილია ჭავჭავაძე', 'მთელი კაცობრიობის უწინდელი ცხოვრება სულ უსარგებლო იქნება, თუ იმათ ცხოვრებიდამ ჩვენ სასარგებლოს არას გამოვიტანთ.', '', ''),
  ('ოტია იოსელიანი', 'ა, ბატონო, გაზაფხული კარზეა მომდგარიდა გაჭინჭყლებული მკაცრად ითხოვს: ან ხვნა თესვას უნდა მიეჩვიოთ, ან ჭამა-სმას უნდა გადაეჩვიოთ!', '', ''),
  ('ოტია იოსელიანი', 'ადამიანებს ერთმანეთის დანდობა და სიყვარული იმიტომ გვჭირდება, რომ ცხოვრებაა დაუნდობელი და კაცთმოძულე.', '', ''),
  ('ოტია იოსელიანი', 'ადამიანი ბუნების შვილია, გარემო-ბუნების ხელყოფა მშობლის ხელყოფაა.', '', ''),
  ('ოტია იოსელიანი', 'ადამიანი მიწას არ უნდა მოაშორო, რომ უკაფავ-უხნავ-უთესველად მომკა არ ისწავლოს.', '', ''),
  ('ოტია იოსელიანი', 'ადამიანი მიწის შვილია და დედას რომ მოსწყდება, ყველა და ყველაფერი დედინაცვლად ექცევა.', '', ''),
  ('ოტია იოსელიანი', 'არავინ იცის, ადამიანები გულწრფელად როდის ტირიან ან იცინიან, მაგრამ ვინც დარდისგან გასიებული ცრემლებს ჩუმად ყლაპავს, გწამდეთ, მეგობრებო!!! ის მართლა ტირის....', '', ''),
  ('ოტია იოსელიანი', 'ბედნიერების წყურვილია, რომ ადამიანს მწყურვალს სტოვებს.', '', ''),
  ('ოტია იოსელიანი', 'ბევრი ვაკეთე და ვაშენე, მეყოფა, აწი სხვებმა აშენონ და აკეთონო,-- რომ იტყვი და ხელებს დაიბან -- იცოდე, იმ დღიდან ანგრევ, თუ რამე აგიშენებია.', '', ''),
  ('ოტია იოსელიანი', 'ბრძენი და უბირი ერთმანეთის გვერდით იზრდებიან, ცხოვრობენ და ბერდებიან. ერთმანეთს ყოველდღე ხვდებიან და არ იცნობენ.', '', ''),
  ('ოტია იოსელიანი', 'გაზაფხული უმერცხლოდაც მოვა, მერცხალი არ მოვა უგაზაფხულოდ.', '', ''),
  ('ოტია იოსელიანი', 'გამოცდილებით, თავგადასულობით რომ ჭკუის სწავლა შეიძლებოდეს, რაც ჩვენს ქვეყანას თავს გადახდენია, ჩვენში, ბრძენი კი არა, სულელი იქნებოდა სანთლით საძებარი.', '', ''),
  ('ოტია იოსელიანი', 'დამარცხებას ათასი გამამართლებელი საბუთიც რო ჰქონდეს, მაინც დამარცხებაა.', '', ''),
  ('ოტია იოსელიანი', 'დედისათვის ყვავის ბახალაც შვილია და არწივის მართვეც, მაგრამ ქვეყნისთვისაა სხვადასხვა.', '', ''),
  ('ოტია იოსელიანი', 'ენაა ერის სისხლი, ჯიში და ჯილაგი.წარმომავლობა,რაც ისტორიას დაავიწყდა,ენას ახსოვს.ერები რომ გადაშენდნენ,მათი ენა ცოცხლობს.ენა მკდარი ერების ძეგლია.', '', ''),
  ('ოტია იოსელიანი', 'ერთ მოყვარე მტერს ასი გადამთიელი მტრის ოდენი ვნების მოტანა შეუძლია.', '', ''),
  ('ოტია იოსელიანი', 'ეშმაკის მოტყუებაც შეიძლება,მაგრამ ეშმაკზე ეშმაკი უნდა იყო.', '', ''),
  ('ოტია იოსელიანი', 'ეჭვით უნდა უყურო ყოველნაირ საკუთარ ღირსებას, თორემ თავმა თავისადმი მიკერძოება იცის და დაგღუპავს.', '', ''),
  ('ოტია იოსელიანი', 'ვინც არ მომკვდარა, მან სიცოცხლის ფასი არ იცის.', '', ''),
  ('ოტია იოსელიანი', 'ბავშვობას და ყრმობას ადამიანი კი არ შორდება, რაც დრო გადის, უახლოვდება. პატარაობისას გინდა, რომ მოზრდილი იყო, მალე დაკაცდე, დამოუკიდებლობა მოიპოვო და ამდენად გაურბიხარ, თორემ მოწიფულობაში თვალი უკან გრჩება და ბავშვობას მართლა თუ ვერ უბრუნდები, იქ კი ტრიალებ.', '', ''),
  ('ოტია იოსელიანი', 'მხოლოდ დაჩოქილ ლოცვას ისმენენ ღმერთები.', '', ''),
  ('ოტია იოსელიანი', 'თავიდან ყველაფერი ძნელია.', '', ''),
  ('ოტია იოსელიანი', 'დიდი ხნით უსაშველოდ შეყვარებულ ქალთან პირველი პაემანი გახსოვთ? გახსოვთ, აბა რა ჯანდაბა დაგავიწყებთ.', '', ''),
  ('ოტია იოსელიანი', 'ოფლისა და სისხლის დაუღვრელად დამოუკიდებლობა არავის დაუმკვიდრებია.', '', ''),
  ('ოტია იოსელიანი', 'ჭირის დღე მძიმე-მძიმედ გადის, მიჯახირობს, მიიზლაზნება, თუ გათენდა, დაღამება არ ეღირსება და თუ დაღამდა - გათენებას არ დაადგება საშველი. მაგრამ ერთი კია - ცხოვრებას ასწრებ. ბედნიერი უკან მოხედვას ვერ ახერხებს, წუთისოფელი ხელიდან ისე გამოეცლება.', '', ''),
  ('ოტია იოსელიანი', 'მგონია, ადამიანი იმაზე ადრეც კი, სანამ ანბანის სწავლას დაიწყებდეს, რაღაცისთვის უკვე მოწოდებულია და მერე ოჯახი, სკოლა და ინსტიტუტი მასში მხოლოდ იმას ზრდიან, რისთვისაც ის გაჩნდა.', '', ''),
  ('ოტია იოსელიანი', 'ერთგული, უღალატო შრომა გამოიღებს ნაყოფს.', '', ''),
  ('ოტია იოსელიანი', 'ყოველ ადამიანს აქვს ამ ქვეყნად კუნჭული, სადაც ის თავისი ცხოვრებით ცხოვრობს.', '', ''),
  ('ოტია იოსელიანი', 'ჭკუა თავშია და არა ხანში.', '', ''),
  ('ოტია იოსელიანი', 'ვისაც ერთი ძირი ხე არ დოურგავს, ის ჩრდილში არ უნდა შეუშვა, სულ პაპანაქებაში უნდა არონიო.', '', ''),
  ('ედიშერ ფუტკარაძე', 'ვისაც უნდა შენთან ადამიანური ურთიერთობის დამყარება, შენარჩუნება ანდა გაფრთხილება – გაუმჯოფესება, ის მოქმედებს ამის შესაბამისად და არ მოგაყენებს ტკივილს.', '"""ჩემი მოსაზრებები"""', 'ურთიერთობა'),
  ('ედიშერ ფუტკარაძე', 'თუ კი ცხოვრობ განმარტოებული ანდა კარჩაკეტელი და ადამიანებთან ნაკლები ურთიერთობა გაქვს, მაშინ ვერც დიდი სიკეთეს ჩაიდენ და ვერც დიდ ცოდვას მათთან მიმართებაში. მთავარია კეთილად დარჩე ხალხმრავლობაში და მით უმეტეს ბოროტი ადამიანების გარემოცვაში.', '"""ჩემი მოსაზრებები"""', 'ურთიერთობა'),
  ('ედიშერ ფუტკარაძე', 'ვერაფერი დაგაშორებს იმ ადამიანს, ვისაც ესმის შენი, შენი თანამოაზრეა და იწონებს შენს გზასა და ნაბიჯებს. ვინც ამას არ აკეთებს, ადრე თუ გვიან მაინც უცხო გახდება შენთვის.', '"""ჩემი მოსაზრებები"""', ''),
  ('ედიშერ ფუტკარაძე', 'ვისაც შეუძლია და აქვს კიდეც თავისი პოზიცია ცხოვრებაში, მას არასდროს სჭირდება და არც მოუწევს ყოფნა ოპოზიციაში.', '"""ჩემი მოსაზრებები"""', '');
